import{_ as i,o as a,c as e,O as t}from"./chunks/framework.c4f51971.js";const u=JSON.parse('{"title":"核心能力","description":"","frontmatter":{},"headers":[],"relativePath":"product/capabilities.md","filePath":"product/capabilities.md","lastUpdated":1775618461000}'),o={name:"product/capabilities.md"};function r(c,l,d,s,p,n){return a(),e("div",null,l[0]||(l[0]=[t('<h1 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h1><h2 id="_1-多租户隔离" tabindex="-1">1. 多租户隔离 <a class="header-anchor" href="#_1-多租户隔离" aria-label="Permalink to &quot;1. 多租户隔离&quot;">​</a></h2><p>平台当前采用 PostgreSQL schema 级多租户模型：</p><ul><li><code>public</code> 负责平台治理和共享底座</li><li>每个正式客户租户拥有自己的独立 schema</li><li>租户之间的脚本、Skill、日志和系统数据默认隔离</li></ul><p>这让平台可以同时承接多个客户，而不是把所有业务混在一个后台里。</p><h2 id="_2-智能大脑执行闭环" tabindex="-1">2. 智能大脑执行闭环 <a class="header-anchor" href="#_2-智能大脑执行闭环" aria-label="Permalink to &quot;2. 智能大脑执行闭环&quot;">​</a></h2><p>平台强调的是“可信执行”，不是“随便聊天”。</p><p>当前闭环包括：</p><ul><li>意图识别</li><li>计划生成</li><li>人工确认</li><li>脚本 / Skill 执行</li><li>执行结果返回</li><li>执行留痕与审计</li></ul><h2 id="_3-脚本注册与-skill-映射" tabindex="-1">3. 脚本注册与 Skill 映射 <a class="header-anchor" href="#_3-脚本注册与-skill-映射" aria-label="Permalink to &quot;3. 脚本注册与 Skill 映射&quot;">​</a></h2><p>平台当前已经打通：</p><ul><li>脚本注册入库</li><li>Skill 可视化查看与编辑</li><li>Skill 动作编排</li><li>租户级启停与绑定</li></ul><p>这意味着平台不再依赖纯硬编码脚本调用，而是在往正式能力目录演进。</p><h2 id="_4-平台模板分发" tabindex="-1">4. 平台模板分发 <a class="header-anchor" href="#_4-平台模板分发" aria-label="Permalink to &quot;4. 平台模板分发&quot;">​</a></h2><p>平台模板已经进入正式链路：</p><ul><li>平台模板发布</li><li>租户安装申请</li><li>租户确认安装</li><li>版本管理</li><li>回滚</li><li>分发日志</li></ul><p>这条链路是后续模板市场、团队版和企业版升级的重要基础。</p><h2 id="_5-公告与日志治理" tabindex="-1">5. 公告与日志治理 <a class="header-anchor" href="#_5-公告与日志治理" aria-label="Permalink to &quot;5. 公告与日志治理&quot;">​</a></h2><p>平台已经具备：</p><ul><li>平台公告与租户公告</li><li>指定租户 / 指定用户投放</li><li>已读状态与已读明细</li><li>登录日志 / 操作日志 / 平台审计</li></ul><p>这让产品不只是能执行，还能治理。</p><h2 id="_6-cli-与本地接入" tabindex="-1">6. CLI 与本地接入 <a class="header-anchor" href="#_6-cli-与本地接入" aria-label="Permalink to &quot;6. CLI 与本地接入&quot;">​</a></h2><p><code>smartflow-cli</code> 当前已经完成最小闭环：</p><ul><li><code>login</code></li><li><code>register</code></li><li><code>list</code></li><li><code>run</code></li><li><code>agent describe</code></li><li><code>agent start</code></li></ul><p>它当前的意义不是“命令行包装器”，而是平台和本地环境之间的桥梁。</p>',25)]))}const _=i(o,[["render",r]]);export{u as __pageData,_ as default};
